func chartMax(data []ChartDataPoint) float64 {
	m := 0.0
	for _, d := range data {
		if d.Value > m {
			m = d.Value
		}
	}
	return m
}

func chartRound(v float64) float64 {
	if v == 0 {
		return 1
	}
	return v
}

